+    #[test]
+    fn is_essential_delegates_to_inner() {
+        #[derive(Debug, Clone, Copy)]
+        struct Essential;
+        impl Widget for Essential {
+            fn render(&self, _: Rect, _: &mut Frame) {}
+            fn is_essential(&self) -> bool {
+                true
+            }
+        }
+
+        let non_essential = Padding::new(Fill('A'), Sides::all(0));
